begin;

-- Generated from the Google AI Studio catalogue on main.
-- Includes all selected IIPM examinations and deliberately excludes any separate CIPMN-branded catalogue.
-- Existing questions are retained for historical attempts, moved out of active positions and deactivated.

-- AIML: Advanced AI & Machine Learning Foundations
values (
  '333a2848-88a9-877d-337e-db80691e6034'::uuid,
  'AIML',
  'Advanced AI & Machine Learning Foundations',
  'This assessment evaluates your understanding of supervised learning algorithms, neural network design, LLM transformers, loss functions, and ethical bias in machine learning systems. Under strict real-time AI proctoring.',
  true
)
on conflict (code) do update
set name = excluded.name,
    description = excluded.description,
    is_active = true,
    updated_at = now();

  id, programme_id, title, instructions, duration_minutes, pass_mark,
  status, max_attempts, randomize_questions, randomize_options,
  allow_self_enrollment, requires_payment
) values (
  '84b5dba2-0e2b-a6a1-0342-7c4abd03e35d'::uuid,
  (select id from public.programmes where code = 'AIML'),
  'Advanced AI & Machine Learning Foundations',
  'Answer every question. This examination is timed and protected by IIPM examination integrity controls. Payment, an approved scholarship coupon or an administrator assignment is required before launch.',
  10,
  70,
  'published',
  1,
  true,
  true,
  false,
  true
)
on conflict (id) do update
set programme_id = excluded.programme_id,
    title = excluded.title,
    instructions = excluded.instructions,
    duration_minutes = excluded.duration_minutes,
    pass_mark = excluded.pass_mark,
    status = excluded.status,
    max_attempts = excluded.max_attempts,
    randomize_questions = excluded.randomize_questions,
    randomize_options = excluded.randomize_options,
    allow_self_enrollment = false,
    requires_payment = true,
    updated_at = now();

with ranked_existing as (
  select id, row_number() over (order by id) as replacement_position
  from public.questions
  where examination_id = '84b5dba2-0e2b-a6a1-0342-7c4abd03e35d'::uuid
)
update public.questions q
set is_active = false,
    position = 100000 + ranked_existing.replacement_position,
    updated_at = now()
from ranked_existing
where q.id = ranked_existing.id;

on conflict (id) do update
set examination_id = excluded.examination_id,
    question_text = excluded.question_text,
    position = excluded.position,
    points = excluded.points,
    is_active = true,
    updated_at = now();

on conflict (id) do update
set question_id = excluded.question_id,
    option_text = excluded.option_text,
    position = excluded.position;

on conflict (question_id) do update
set correct_option_id = excluded.correct_option_id,
    updated_at = now();

update public.exam_prices
set is_default = false, updated_at = now()
where examination_id = '84b5dba2-0e2b-a6a1-0342-7c4abd03e35d'::uuid
  and currency <> 'NGN'
  and is_default = true;

  id, examination_id, currency, amount_minor, country_codes,
  is_default, is_active, effective_from, effective_to
) values (
  '08103529-1f8b-f68a-81e4-dce99dff7a1c'::uuid,
  '84b5dba2-0e2b-a6a1-0342-7c4abd03e35d'::uuid,
  'NGN',
  2500000,
  array['NG']::text[],
  true,
  true,
  now(),
  null
)
on conflict (examination_id, currency) do update
set amount_minor = 2500000,
    country_codes = array['NG']::text[],
    is_default = true,
    is_active = true,
    effective_from = least(public.exam_prices.effective_from, now()),
    effective_to = null,
    updated_at = now();

