    effective_to = null,
    updated_at = now();

do $$
declare
  v_record record;
  v_actual integer;
begin
  for v_record in
    select * from (values
      ('84b5dba2-0e2b-a6a1-0342-7c4abd03e35d'::uuid, 'AIML', 5),
      ('b5233a01-d982-d4ec-fd4c-729bf2bd8bc9'::uuid, 'CYBER', 5),
      ('9c332310-f648-82fe-26e4-3fb3c8659603'::uuid, 'SWEETH', 5),
      ('20000000-0000-4000-8000-000000000101'::uuid, 'HRMFC', 5),
      ('61265cc5-3b98-ad6c-85bc-7c145c7d06a1'::uuid, 'CHRMG', 50),
      ('20000000-0000-4000-8000-000000000102'::uuid, 'CHRMP', 75),
      ('e979cf82-30f3-2768-3891-b9cc5e51bde2'::uuid, 'PM', 50),
      ('1d178fed-f007-6b21-8c07-e8a8301f0c05'::uuid, 'PCIT', 75),
      ('0dadec7a-f11f-61d1-eb5d-e6e61d17d023'::uuid, 'RMP', 75),
      ('722191d6-dbc7-f961-0b3e-b4168c60824b'::uuid, 'QMP', 75),
      ('7816b3d7-602f-ddb0-345d-1a921c5a3fa6'::uuid, 'PCM', 75)
    ) as expected(examination_id, programme_code, expected_questions)
  loop
    select count(*) into v_actual
    from public.questions
    where examination_id = v_record.examination_id and is_active = true;

    if v_actual <> v_record.expected_questions then
      raise exception 'Question count validation failed for %: expected %, found %.',
        v_record.programme_code, v_record.expected_questions, v_actual;
    end if;

    if not exists (
      select 1 from public.examinations e
      where e.id = v_record.examination_id
        and e.status = 'published'
        and e.requires_payment = true
        and e.allow_self_enrollment = false
    ) then
      raise exception 'Payment and publication configuration failed for %.', v_record.programme_code;
    end if;

    if not exists (
      select 1 from public.exam_prices ep
      where ep.examination_id = v_record.examination_id
        and ep.currency = 'NGN'
        and ep.amount_minor = 2500000
        and ep.is_default = true
        and ep.is_active = true
    ) then
      raise exception 'NGN 25,000 price validation failed for %.', v_record.programme_code;
    end if;
  end loop;
end;
$$;

