  ('fd3167c9-69ca-18f6-cd8d-4691e3cab56c'::uuid, 'b9d39c72-58e7-03b2-610b-7b45ca54564f'::uuid, 'Symmetric uses the same key for encryption and decryption; Asymmetric uses a mathematically linked public-private key pair.', 1),
  ('862918bb-61e0-4a1e-558a-d7cc721ed2cd'::uuid, 'b9d39c72-58e7-03b2-610b-7b45ca54564f'::uuid, 'Symmetric is used only for data in transit; Asymmetric is strictly used for encrypting local database storage backups.', 2),
  ('319c804d-dcd0-e49f-7d16-906ba3a35481'::uuid, 'b9d39c72-58e7-03b2-610b-7b45ca54564f'::uuid, 'Symmetric is slow but highly secure; Asymmetric is exceptionally fast but prone to rainbow table attacks.', 3),
  ('02d5aa64-4e22-906a-a859-1e0be7065c52'::uuid, 'b9d39c72-58e7-03b2-610b-7b45ca54564f'::uuid, 'Symmetric relies on quantum entanglement properties; Asymmetric relies on high prime factorization complexity.', 4),
  ('65f2ccb3-13f7-c0b1-483b-2af94fd3c0dd'::uuid, '81bd52d3-bcb0-c8dc-4696-53261739c869'::uuid, 'It injects executable scripts into database strings; mitigated by using strict input HTML entity validation.', 1),
  ('a5afdf22-eb55-5977-42b8-2b1a6da3e85c'::uuid, '81bd52d3-bcb0-c8dc-4696-53261739c869'::uuid, 'It tricks an authenticated user''s browser into executing an unauthorized command on a trusted web application; mitigated by anti-CSRF tokens and SameSite cookie attributes.', 2),
  ('a7515e75-548c-0f85-4dbb-034e4c41fb71'::uuid, '81bd52d3-bcb0-c8dc-4696-53261739c869'::uuid, 'It intercepts unencrypted packets over local Wi-Fi networks; mitigated by setting up TLS / SSL configurations.', 3),
  ('bb1718e5-d139-f3e0-60ea-0c415afd7c71'::uuid, '81bd52d3-bcb0-c8dc-4696-53261739c869'::uuid, 'It floods servers with half-open TCP connections; mitigated by deploying reverse proxies and rate limiters.', 4),
  ('bde4cd95-3f0d-e6f3-a1a6-b217dce6fa3d'::uuid, '1e1600f9-4b7a-8f88-e9bf-7208218e5006'::uuid, 'To remove all firewalls and depend purely on cloud endpoints.', 1),
  ('33d734cb-051b-3402-5b59-840ac764b480'::uuid, '1e1600f9-4b7a-8f88-e9bf-7208218e5006'::uuid, 'To eliminate password policies and shift to biometric hardware keys exclusively.', 2),
  ('f5e53ffa-fb8b-5510-f414-17d65e1dab95'::uuid, '1e1600f9-4b7a-8f88-e9bf-7208218e5006'::uuid, 'To operate under the continuous principle of "never trust, always verify" regardless of whether access originates inside or outside the network.', 3),
  ('81176620-e178-684b-4130-baa483d6e2b3'::uuid, '1e1600f9-4b7a-8f88-e9bf-7208218e5006'::uuid, 'To secure databases by enforcing 256-bit AES encryption across public columns.', 4),
  ('4ce9334f-4c26-2f77-4fb0-8785fdd5ab71'::uuid, '8c1ab622-2a9d-68fe-321c-2f15d9145c0e'::uuid, 'Applying client-side JavaScript regex sanitization prior to form submissions.', 1),
  ('f8380f49-128a-91c3-f05c-621148a81893'::uuid, '8c1ab622-2a9d-68fe-321c-2f15d9145c0e'::uuid, 'Using parameterized queries / prepared statements instead of directly concatenating user input into SQL commands.', 2),
  ('d8554dc1-0ad4-b875-2d28-dfa54a9c0355'::uuid, '8c1ab622-2a9d-68fe-321c-2f15d9145c0e'::uuid, 'Restricting table reads using read-only database connections.', 3),
  ('bd206882-f027-6284-96a2-5b24bf2acb39'::uuid, '8c1ab622-2a9d-68fe-321c-2f15d9145c0e'::uuid, 'Using Base64 encoding for all search queries sent from browser sessions.', 4),
  ('716b657e-ec4d-ff64-2165-32848c987cbc'::uuid, '645a0c6c-ebae-0fd3-20c5-4789dcf719a9'::uuid, 'To increase the speed of the hashing algorithms during high-traffic user logins.', 1),
  ('1ebb4159-873b-fc35-4b95-fe2da37259cc'::uuid, '645a0c6c-ebae-0fd3-20c5-4789dcf719a9'::uuid, 'To encrypt the password so that it can be reversed back to plain text if the user loses it.', 2),
  ('39200fd7-cc8a-5385-ec4f-6aedd2c8871f'::uuid, '645a0c6c-ebae-0fd3-20c5-4789dcf719a9'::uuid, 'To add unique, random data to each password so that identical passwords result in different hashes, defeating precomputed rainbow tables.', 3),
  ('9cb71966-9e60-b4af-a0b4-1d68f40a0d3b'::uuid, '645a0c6c-ebae-0fd3-20c5-4789dcf719a9'::uuid, 'To compress the length of the resulting database records for better storage efficiency.', 4)
