values
  ('1587aa85-f1ce-1917-8ed3-53bf815fc2de'::uuid, 'e1a2bffd-60a3-30b4-7361-715de43ed17f'::uuid, 'Advise the employee to submit a transfer request first, then talk to the manager.', 1),
  ('e87228cf-9054-6625-4b80-aa6be449df0b'::uuid, 'e1a2bffd-60a3-30b4-7361-715de43ed17f'::uuid, 'Reassure the employee of anti-retaliation policies, document the grievance, and initiate a prompt, objective investigation.', 2),
  ('284c3a34-2f9a-bf28-5459-38d9907c17dc'::uuid, 'e1a2bffd-60a3-30b4-7361-715de43ed17f'::uuid, 'Confront the manager immediately in an informal meeting and demand that they apologize to the employee.', 3),
  ('2eaa7b3b-ddbb-abbf-2b18-a8e89d23bad1'::uuid, 'e1a2bffd-60a3-30b4-7361-715de43ed17f'::uuid, 'Advise the employee to resolve the issue directly with the manager to preserve the working relationship.', 4),
  ('ff19af9b-aee4-3861-b986-3f7aa2bd27af'::uuid, '28b6a3ca-39ed-eed4-7d7e-566c281ae334'::uuid, 'Forcing: Instruct the project manager to select one designer''s styling rules and mandate compliance.', 1),
