  ('ba781f94-8998-5f41-0e14-9dd9d1a7c690'::uuid, '98536c25-d06b-c9de-1c42-03ac8a648d00'::uuid, 'Job Ranking Method', 3),
  ('613451af-a6f3-2c47-67cf-8121237a6c51'::uuid, '98536c25-d06b-c9de-1c42-03ac8a648d00'::uuid, 'Market Pricing Method', 4),
  ('fe0eeab0-5dca-ae1e-0508-60262719d85d'::uuid, '91c2c7a2-0400-d49b-8567-d4100520ae7d'::uuid, 'Target base salaries at the 95th percentile of the market, regardless of incentive options.', 1),
  ('0c9cec3c-2b87-ac8c-2a5d-54346e10d7da'::uuid, '91c2c7a2-0400-d49b-8567-d4100520ae7d'::uuid, 'Benchmark base salaries at the 50th percentile (market median), but design a high-value performance-based variable pay and comprehensive benefits package.', 2),
  ('992c4dde-f7b2-9f01-4339-67396deda130'::uuid, '91c2c7a2-0400-d49b-8567-d4100520ae7d'::uuid, 'Set base salaries at the 25th percentile to minimize fixed costs and rely fully on discretionary bonuses.', 3),
  ('fc4bcbee-6a3b-1c5e-bf41-42fb3b8a8b44'::uuid, '91c2c7a2-0400-d49b-8567-d4100520ae7d'::uuid, 'Copy the compensation structures of international companies, irrespective of local cost-of-living data.', 4),
  ('f4911ddf-3192-a274-7f8f-cf642977161c'::uuid, '108e99c7-357c-e96e-5f1e-ac30af692f60'::uuid, 'There is no risk since they have "assistant" in their title; maintain current exempt classification.', 1),
  ('4680da95-0292-b24e-95ba-0410ce39c5e5'::uuid, '108e99c7-357c-e96e-5f1e-ac30af692f60'::uuid, 'High risk of wage-and-hour violations; reclassify them as "non-exempt" based on the duties test, track their hours, and pay appropriate overtime.', 2),
  ('3549ccdd-3297-3618-78e8-2755d72dbd40'::uuid, '108e99c7-357c-e96e-5f1e-ac30af692f60'::uuid, 'Ask the assistants to sign a voluntary waiver agreeing to waive their rights to overtime pay.', 3),
  ('13d0d551-a2cb-bad9-4fd4-11706174c0e8'::uuid, '108e99c7-357c-e96e-5f1e-ac30af692f60'::uuid, 'Change their job titles to "Executive Director of Calendars" to justify the exempt classification.', 4),
  ('38921d6e-eeb1-17dc-08dd-4e83c78310f5'::uuid, '882a087c-1463-846f-852d-05fa84520c7f'::uuid, 'An insurance plan with zero deductibles but high monthly premiums, coupled with restricted clinic selections.', 1),
  ('deffa3ca-1844-add6-f692-daacee6b1254'::uuid, '882a087c-1463-846f-852d-05fa84520c7f'::uuid, 'A High-Deductible Health Plan (HDHP) combined with a tax-advantaged Health Savings Account (HSA) that receives employer contributions.', 2),
  ('ed37cd21-09ed-2ace-d514-2732d2d6b049'::uuid, '882a087c-1463-846f-852d-05fa84520c7f'::uuid, 'A plan that covers dental and vision care only, leaving general medical expenses to be paid out-of-pocket.', 3),
  ('61c74e89-7d53-d7f6-76b6-745a9803b2f0'::uuid, '882a087c-1463-846f-852d-05fa84520c7f'::uuid, 'An plan that requires employees to obtain pre-approval from HR for all medical visits.', 4),
  ('5b54f188-1a07-ce0b-856a-84906bcecb1b'::uuid, '1e8271cf-4848-c385-e2e1-edd7724c9177'::uuid, 'A traditional commissions-only model that focuses strictly on cash incentives.', 1),
  ('eb5eba88-bcdc-aeef-d51f-d87f17ed08b8'::uuid, '1e8271cf-4848-c385-e2e1-edd7724c9177'::uuid, 'A Total Rewards framework that integrates competitive base pay, sales commissions, paid certifications, and career mentoring.', 2),
  ('8f85fbba-3023-0c2b-b2ce-20b048af711f'::uuid, '1e8271cf-4848-c385-e2e1-edd7724c9177'::uuid, 'A non-cash model that replaces all sales bonuses with company recognition certificates.', 3),
  ('e0de958d-5ad3-bff7-723b-1cc2fb50bc00'::uuid, '1e8271cf-4848-c385-e2e1-edd7724c9177'::uuid, 'A plan where stipends are deducted from commissions to fund mandatory training sessions.', 4),
  ('0ac48df7-48be-7da7-a36e-7b951805b604'::uuid, '8e52a22a-2967-35aa-6c16-4e8477f9323b'::uuid, 'Advise the employee that salary discussions are prohibited and threaten disciplinary action.', 1),
  ('95a33660-dbd3-d32f-ecb1-59d8bc3875ce'::uuid, '8e52a22a-2967-35aa-6c16-4e8477f9323b'::uuid, 'Conduct a pay equity review, identify objective factors (e.g., certifications, specialized experience, market fluctuations at hire), and adjust pay if unjustified disparities are found.', 2),
  ('c2acc0ba-a2d3-d1b3-25a1-8bc2da9fa0b7'::uuid, '8e52a22a-2967-35aa-6c16-4e8477f9323b'::uuid, 'Explain that new hires always make more due to market inflation, and advise them to wait for the annual review.', 3),
  ('376522c2-7a1c-6b1f-106b-9cd53215bf8f'::uuid, '8e52a22a-2967-35aa-6c16-4e8477f9323b'::uuid, 'Immediately lower the new hire''s salary to match the existing employee''s rate.', 4),
  ('5ce8cda4-e232-5330-5109-f2d35e340e4d'::uuid, '45eedf84-da51-eb91-980b-cc4aa9979b4f'::uuid, 'Local Market Approach: Pay the manager the local going rate of the host country, regardless of home country standards.', 1),
  ('a0334f06-1e37-3113-cc01-9190d97ab8e3'::uuid, '45eedf84-da51-eb91-980b-cc4aa9979b4f'::uuid, 'Balance Sheet Approach: Keep the manager on the home-country salary scale, while providing cost-of-living adjustments, housing allowances, and tax equalization.', 2),
  ('530fb315-2890-005e-6809-05f2d00d197e'::uuid, '45eedf84-da51-eb91-980b-cc4aa9979b4f'::uuid, 'Lump-Sum Approach: Give the manager a flat cash allowance and require them to handle all salary, tax, and relocation logistics independently.', 3),
  ('a1675314-57c0-34bb-2f70-c2c5cda06d71'::uuid, '45eedf84-da51-eb91-980b-cc4aa9979b4f'::uuid, 'Negotiation Approach: Agree on a custom, ad-hoc salary rate through individual bargaining without structured policies.', 4),
  ('bb1728e9-f83f-2021-15af-1d8a98881a32'::uuid, 'c32c9279-0175-a667-d841-7cadf92eb70b'::uuid, 'To serve as the direct, sole mathematical basis for calculating annual salary increases and promotion decisions.', 1),
  ('7701f28a-fb53-b00e-1aa3-dc454a258abc'::uuid, 'c32c9279-0175-a667-d841-7cadf92eb70b'::uuid, 'To provide broad developmental feedback on leadership behaviors, communication style, and collaboration, separate from pay evaluations.', 2),
  ('298ca3d2-0508-9e82-8612-dc2d32c4c472'::uuid, 'c32c9279-0175-a667-d841-7cadf92eb70b'::uuid, 'To identify and document low-performing managers for immediate placement on Performance Improvement Plans.', 3),
  ('63b2d725-197c-5082-cfc9-f1bcc97d4bdf'::uuid, 'c32c9279-0175-a667-d841-7cadf92eb70b'::uuid, 'To allow team members to anonymously grade their supervisors for disciplinary reviews.', 4),
  ('f82a6ac1-f5ea-ef43-a156-9aa53a4572bb'::uuid, '8833cff3-f274-4fb8-5089-e58e66a34d05'::uuid, 'Order the engineering department to raise their ratings to match the administrative department.', 1),
  ('0b76fc49-26bc-4f5b-44e4-04c8bc6e5d82'::uuid, '8833cff3-f274-4fb8-5089-e58e66a34d05'::uuid, 'Introduce structured performance calibration sessions where managers discuss and justify their ratings based on objective evidence.', 2),
  ('a3b0fc9f-243f-55d2-ea65-481997c538ec'::uuid, '8833cff3-f274-4fb8-5089-e58e66a34d05'::uuid, 'Enforce a rigid forced-ranking system where 15% of all employees must be rated as low performers.', 3),
  ('80e3b229-d9c1-29c0-efe0-9fa972583b03'::uuid, '8833cff3-f274-4fb8-5089-e58e66a34d05'::uuid, 'Instruct the payroll department to cap bonuses regardless of performance ratings.', 4),
  ('e01b810b-b07d-a6fd-12cf-4c37fcbb4b2d'::uuid, 'cdd31db7-82c1-427b-7632-e4435b241c68'::uuid, 'It is faster to design and requires zero supervisor training.', 1),
  ('11230a52-f711-fa54-f1c4-86d1a3d2de29'::uuid, 'cdd31db7-82c1-427b-7632-e4435b241c68'::uuid, 'It anchors rating levels to specific, observable behavioral examples, reducing supervisor subjectivity and bias.', 2),
  ('3069afa5-aee4-d548-a1b3-dfc5e32e7282'::uuid, 'cdd31db7-82c1-427b-7632-e4435b241c68'::uuid, 'It automatically calculates employee bonuses based on mathematical algorithms.', 3),
  ('00b027ce-2277-86c4-3ffa-dd1eb04b833c'::uuid, 'cdd31db7-82c1-427b-7632-e4435b241c68'::uuid, 'It allows employees to rate themselves without supervisor intervention.', 4),
  ('c452b426-b70c-95a4-4deb-0c71cb40c426'::uuid, '96a76c91-aab7-a117-4df5-3cbe9d2e6e06'::uuid, 'Approve the PIP immediately to start the termination documentation process.', 1),
  ('0e54fa81-bca0-b550-a959-59c1c4312975'::uuid, '96a76c91-aab7-a117-4df5-3cbe9d2e6e06'::uuid, 'Advise the supervisor to hold an informal, supportive meeting with the assistant to discuss the sudden performance drop, identify root causes, and offer guidance.', 2),
  ('46c006c6-0165-8769-a01c-e9f2a39d45af'::uuid, '96a76c91-aab7-a117-4df5-3cbe9d2e6e06'::uuid, 'Reassign the assistant to a non-administrative role to bypass performance issues.', 3),
  ('37acf939-5d30-f2a7-abf5-449b7b5677b0'::uuid, '96a76c91-aab7-a117-4df5-3cbe9d2e6e06'::uuid, 'Issue an immediate formal written warning and log it in the employee''s permanent file.', 4),
  ('bb548b2d-cd09-3d68-db54-b54dd635fe55'::uuid, '50069271-4623-5996-284a-e1ae95649a79'::uuid, 'It increases operational costs by requiring too many physical evaluation sheets.', 1),
  ('98af5106-3d50-d3b5-d728-247f45075eda'::uuid, '50069271-4623-5996-284a-e1ae95649a79'::uuid, 'It destroys teamwork, encourages internal competition, increases voluntary turnover of high-performers, and exposes the firm to legal risks.', 2),
  ('f242599f-3a8d-c324-76bf-1ad7b5bc9b64'::uuid, '50069271-4623-5996-284a-e1ae95649a79'::uuid, 'It is highly favored by labor unions and will lead to excessive collective bargaining demands.', 3),
  ('e0cce1fe-63e8-41a0-0606-37bcad5317da'::uuid, '50069271-4623-5996-284a-e1ae95649a79'::uuid, 'It has no impact on culture and is the industry standard for all major technology companies.', 4),
  ('6d81e687-8e77-5925-e653-2c5d2d8b26ef'::uuid, 'c3ae08fd-b0b3-ad16-809e-f2f0d82b8bdb'::uuid, 'Abolish all performance evaluations and allocate salary increases strictly based on tenure.', 1),
  ('59830874-8cfc-382a-d883-26310e80d025'::uuid, 'c3ae08fd-b0b3-ad16-809e-f2f0d82b8bdb'::uuid, 'Transition from annual appraisals to a continuous feedback model with structured monthly or bi-weekly check-ins and shared OKRs.', 2),
  ('12285f70-4c1d-2d1b-eae1-951c9189392c'::uuid, 'c3ae08fd-b0b3-ad16-809e-f2f0d82b8bdb'::uuid, 'Mandate that supervisors send performance check-in emails every Monday morning.', 3),
  ('9cdd5f0b-b0b1-bae5-f910-e6dc0da7d6ca'::uuid, 'c3ae08fd-b0b3-ad16-809e-f2f0d82b8bdb'::uuid, 'Create an online portal where employees can view their manager''s notes in real-time without scheduling meetings.', 4),
  ('08bf60b1-e9f7-bfb0-54ca-25a7bff7738a'::uuid, '643e2183-76f2-61a0-f5ee-a0f9c1dfc995'::uuid, 'Coaching is long-term and informal; Mentoring is short-term and focused strictly on technical skills.', 1),
  ('eecad3d9-574e-523a-645a-db479d5d5e57'::uuid, '643e2183-76f2-61a0-f5ee-a0f9c1dfc995'::uuid, 'Coaching is typically short-term, structured, and focused on specific task performance; Mentoring is long-term, development-oriented, and focused on career pathing.', 2),
  ('303860df-e380-5d52-6fe1-38b52fb1b33d'::uuid, '643e2183-76f2-61a0-f5ee-a0f9c1dfc995'::uuid, 'Coaching is handled by external consultants; Mentoring is handled exclusively by HR staff.', 3),
  ('860efa4e-265d-8268-54b3-2ddf2d2e19a6'::uuid, '643e2183-76f2-61a0-f5ee-a0f9c1dfc995'::uuid, 'There is no difference; they are synonymous terms in executive development.', 4),
  ('42338b83-a04c-c062-d9e3-83ba95373f10'::uuid, '4b7b74cf-798f-4192-0209-efc2ad17ca1d'::uuid, 'Isolated Departmental Goals: Allow each manager to set team tasks independently of other divisions.', 1),
  ('13ef56b8-a0ff-3973-5855-c07f2e82955f'::uuid, '4b7b74cf-798f-4192-0209-efc2ad17ca1d'::uuid, 'Cascading Goals: Align organizational strategic objectives to division KPIs, department targets, and individual performance goals.', 2),
  ('8668c2b4-2ee8-fb4c-a062-d846567eab63'::uuid, '4b7b74cf-798f-4192-0209-efc2ad17ca1d'::uuid, 'Ad-hoc Goals: Encourage employees to set weekly personal tasks without corporate alignments.', 3),
  ('6d9dc38b-951e-3ab0-a634-fd034b2062f0'::uuid, '4b7b74cf-798f-4192-0209-efc2ad17ca1d'::uuid, 'Bottom-up Mandate: Aggregate individual personal goals and define the corporate strategy based on employee preferences.', 4),
  ('8354fcf7-fb45-b8d0-586f-edfd747f389b'::uuid, '92d05c12-8b01-d99e-dc80-5515ecd0a0ee'::uuid, 'Review online catalogs and sign a contract with the highest-rated training vendor.', 1),
  ('6cf950bb-bd6f-a88b-7615-50fa387241e4'::uuid, '92d05c12-8b01-d99e-dc80-5515ecd0a0ee'::uuid, 'Conduct a thorough Training Needs Assessment (TNA) to analyze the performance gap, target audience skills, and operational challenges.', 2),
  ('e2279336-7200-7cca-3d6e-e9215d9b00e3'::uuid, '92d05c12-8b01-d99e-dc80-5515ecd0a0ee'::uuid, 'Design interactive slide decks and forklift training manuals for the operators.', 3),
  ('4b12aff0-480e-b84d-aa04-9b9f4e0aefc8'::uuid, '92d05c12-8b01-d99e-dc80-5515ecd0a0ee'::uuid, 'Organize a pilot training session with the most experienced forklift operators.', 4),
  ('6575a3c7-1c9b-7541-5ecf-92fa78f85a9a'::uuid, '781f232f-ee06-e61c-a3df-76e392e03050'::uuid, 'Structuring the course around abstract theories, rote-memorization, and grades.', 1),
  ('35f856ce-be99-ea8f-84fc-68f7a24338e9'::uuid, '781f232f-ee06-e61c-a3df-76e392e03050'::uuid, 'Designing problem-centered, experiential modules where managers can apply their existing professional expertise to solve real scenarios.', 2),
  ('0a47a1a8-828c-a0c0-114f-3a26ec7d2849'::uuid, '781f232f-ee06-e61c-a3df-76e392e03050'::uuid, 'Enforcing strict daily attendance quotas with formal reprimands for missing lectures.', 3),
  ('1e338d81-21bb-66ec-7050-72a03eab8fc1'::uuid, '781f232f-ee06-e61c-a3df-76e392e03050'::uuid, 'Keeping the training content uniform and standardized, without allowing self-directed pacing.', 4),
  ('34a1ec1c-4e91-9cb9-7721-6c1c75f6db51'::uuid, 'ec329323-c55f-e0f3-34f3-a10f38934b85'::uuid, 'Level 1: Reaction (satisfaction surveys)', 1),
  ('0a848738-1da4-0345-6a49-f2c76119404a'::uuid, 'ec329323-c55f-e0f3-34f3-a10f38934b85'::uuid, 'Level 2: Learning (post-training knowledge quizzes)', 2),
  ('1fdcd18a-60d9-33c1-d547-a85a249637bc'::uuid, 'ec329323-c55f-e0f3-34f3-a10f38934b85'::uuid, 'Level 3: Behavior (on-the-job behavioral audits and 360-degree feedback reviews)', 3),
  ('201e9f92-eacd-2182-9804-6d9c2dd356a5'::uuid, 'ec329323-c55f-e0f3-34f3-a10f38934b85'::uuid, 'Level 4: Results (business unit productivity metrics)', 4),
  ('d664da3a-ba46-1e5b-5352-f686edee281d'::uuid, '225e0ad8-5a5d-40b9-e5d8-9b2407870eb3'::uuid, 'Schedule live, full-day classroom lectures at regional hotels over the next three months.', 1),
  ('963bae74-a9b5-def5-2da7-1ab5f3d9c07d'::uuid, '225e0ad8-5a5d-40b9-e5d8-9b2407870eb3'::uuid, 'Deploy bite-sized, mobile-optimized microlearning modules on the corporate LMS with interactive simulated checks.', 2),
  ('dc5058fe-8deb-2b62-702c-b3ef638d36f6'::uuid, '225e0ad8-5a5d-40b9-e5d8-9b2407870eb3'::uuid, 'Distribute printed technical manuals and require clerks to study them in their personal hours.', 3),
  ('fec310e6-a8b9-0acc-1cc5-34d03ee635b1'::uuid, '225e0ad8-5a5d-40b9-e5d8-9b2407870eb3'::uuid, 'Deliver the training via a sequence of weekly corporate emails without assessments.', 4),
  ('9f2bd4cf-0234-fc79-3dd0-8cdc5f362fca'::uuid, 'd50d3237-b240-81b9-1499-6d23ea534c52'::uuid, 'Allow junior analysts and executives to self-select matches and meet informally without guidelines.', 1),
  ('9246cdac-652a-718d-1648-13ebc3b6ef98'::uuid, 'd50d3237-b240-81b9-1499-6d23ea534c52'::uuid, 'Establish a formal pairing system based on career mapping, define clear goals and meeting templates, and monitor progress.', 2),
  ('a45ae519-652f-e265-1366-8370821d7444'::uuid, 'd50d3237-b240-81b9-1499-6d23ea534c52'::uuid, 'Require senior partners to grade the weekly performance of their junior mentees for the HR files.', 3),
  ('cdd4ce26-b479-3188-95fb-9afd4759e837'::uuid, 'd50d3237-b240-81b9-1499-6d23ea534c52'::uuid, 'Limit the mentorship program to the highest-performing junior analyst each year.', 4),
  ('1a765560-3d62-3467-7429-6af3c4b9fc7f'::uuid, '1d1a8a93-7dd7-1fd2-68a3-e572fa941047'::uuid, 'Deny the leave if the department is currently understaffed, and suggest they resign.', 1),
  ('ca57f710-7c75-799c-ce7b-87216e52a982'::uuid, '1d1a8a93-7dd7-1fd2-68a3-e572fa941047'::uuid, 'Review and administer the leave under family/medical leave laws (such as FMLA or national equivalents), maintaining their health benefits and guaranteeing their role or equivalent upon return.', 2),
  ('a3cce143-c913-1e14-d6bc-47333c8f4b8e'::uuid, '1d1a8a93-7dd7-1fd2-68a3-e572fa941047'::uuid, 'Approve the leave but suspend their health insurance benefits during their absence.', 3),
  ('331ce0d7-b7bb-3727-5b01-9838a6e85f37'::uuid, '1d1a8a93-7dd7-1fd2-68a3-e572fa941047'::uuid, 'Approve the leave only on the condition that the employee works part-time from home.', 4),
  ('3ac735ff-79e6-c8ca-32df-a37319beb0c0'::uuid, '0a29e9a7-990c-9490-f780-4bafb6a8ac0f'::uuid, 'Support the manager''s production goals and advise the operator to work carefully.', 1),
  ('dc46ac15-a35e-b23f-fb58-f5bc254f0b47'::uuid, '0a29e9a7-990c-9490-f780-4bafb6a8ac0f'::uuid, 'Ensure the belt is shut down immediately, report the hazard to the safety officer, and protect the operator from any retaliation.', 2),
  ('f68f16b4-a255-f0b6-d5a1-31469faf61f1'::uuid, '0a29e9a7-990c-9490-f780-4bafb6a8ac0f'::uuid, 'Advise the operator to file an external government lawsuit without notifying internal safety teams.', 3),
  ('0f732bd3-9f0f-1e0e-181a-af7f1532d083'::uuid, '0a29e9a7-990c-9490-f780-4bafb6a8ac0f'::uuid, 'Instruct the operator to find a colleague willing to operate the belt instead.', 4),
  ('90ae4298-e5ad-1f72-6111-6a9cde59af1f'::uuid, '502ac78d-3f96-235c-b4e8-228f38a74765'::uuid, 'Management can change benefits unilaterally at any time under executive authority.', 1),
  ('20b1af62-fbe7-4e40-a1d5-04b59e5e13c2'::uuid, '502ac78d-3f96-235c-b4e8-228f38a74765'::uuid, 'Benefits are mandatory subjects of collective bargaining; HR must consult union representatives and negotiate in good faith before making changes.', 2),
  ('1b21e36a-7a3d-e132-53b7-65c8a4965b89'::uuid, '502ac78d-3f96-235c-b4e8-228f38a74765'::uuid, 'Advise the site director to announce the changes quietly to avoid union opposition.', 3),
  ('196f04a6-845f-ed4d-54b0-66af6b693df3'::uuid, '502ac78d-3f96-235c-b4e8-228f38a74765'::uuid, 'Terminate the collective bargaining agreement to simplify benefits administration.', 4),
  ('7e946eae-c9c0-d361-0f76-4dec409a9283'::uuid, '71537dc8-35ab-8e41-8af4-49207c61c089'::uuid, '5%', 1),
  ('4456d869-ad0a-4b9a-8007-e3cbd47b926f'::uuid, '71537dc8-35ab-8e41-8af4-49207c61c089'::uuid, '10%', 2),
  ('6a3da64d-c0cb-f6a4-8882-db718a71714c'::uuid, '71537dc8-35ab-8e41-8af4-49207c61c089'::uuid, '20%', 3),
  ('3870e54f-20f6-8c48-6126-976e03e21d93'::uuid, '71537dc8-35ab-8e41-8af4-49207c61c089'::uuid, '15%', 4),
  ('62bfd59a-0462-b520-ba81-f946fc95e812'::uuid, 'b946e422-f179-c425-d5c7-f8f19e0aaff3'::uuid, 'Dismiss the complaint immediately because critiquing work is part of a manager''s job.', 1),
  ('b002d51a-1f3e-de1a-0f92-ea7a3e079434'::uuid, 'b946e422-f179-c425-d5c7-f8f19e0aaff3'::uuid, 'Conduct a thorough review of the manager''s behavior against workplace conduct policies, interview witnesses, and guide the manager on professional coaching.', 2),
  ('95423359-3990-efe4-ef5d-7167c723aa6d'::uuid, 'b946e422-f179-c425-d5c7-f8f19e0aaff3'::uuid, 'Inform the employee that they must adapt to different management styles or seek other roles.', 3),
  ('0f4474ef-c4c4-4a8e-61e1-350047582a1a'::uuid, 'b946e422-f179-c425-d5c7-f8f19e0aaff3'::uuid, 'Immediately suspend the manager without checking the claims to demonstrate safety.', 4)
