  ('d9367aef-ea47-5d36-e73c-8c12d18b2531'::uuid, '7174779a-e808-6e0d-1a61-17bea1724a58'::uuid, 'Restrict bonus distributions to the top 5% of individual contributors and make the distribution confidential.', 3),
  ('f0669f1f-6c31-af6e-7730-95890a310eb3'::uuid, '7174779a-e808-6e0d-1a61-17bea1724a58'::uuid, 'Offer employees additional paid time off in lieu of financial bonuses to preserve cash reserves.', 4),
  ('feebaecf-8768-3b70-9511-5ad6811ab160'::uuid, '34358eb8-56d8-1f98-2b7e-9f3df94b3a27'::uuid, 'Immediately cancel all expat compensation packages and transition the executives to local base salaries.', 1),
  ('8688a3a5-bc76-1f43-4591-59b5d24ff055'::uuid, '34358eb8-56d8-1f98-2b7e-9f3df94b3a27'::uuid, 'Perform a comprehensive Global Mobility Audit, standardize allowances (e.g., cost-of-living, housing) using independent benchmark index data, and utilize a "Local-Plus" or tax-equalized compensation model.', 2),
  ('4f445bce-9130-7530-708f-e6a9c8e27486'::uuid, '34358eb8-56d8-1f98-2b7e-9f3df94b3a27'::uuid, 'Instruct the finance department to manually write off the tax penalties to avoid disrupting executive relations.', 3),
  ('ddc0974e-b78a-c6b5-ee5d-bd15585e76d3'::uuid, '34358eb8-56d8-1f98-2b7e-9f3df94b3a27'::uuid, 'Disclose the compensation details of the affected executives to the internal audit committee to force voluntary re-negotiation.', 4),
  ('c108190d-c851-e658-2c87-50e84edc6764'::uuid, 'f80cdfce-3aaf-15f6-659a-b6acee5b3157'::uuid, 'Offer a performance bonus paid annually based on individual lab productivity metrics.', 1),
  ('b68daf53-b4b9-0be1-4805-4fae74d5ec59'::uuid, 'f80cdfce-3aaf-15f6-659a-b6acee5b3157'::uuid, 'Design a structured "Stay Bonus" with a deferred vesting schedule, payable only upon the successful completion of the FDA approval process, coupled with long-term equity grants.', 2),
  ('b0c52a3c-e7ca-21f3-0811-5e9efa7314bc'::uuid, 'f80cdfce-3aaf-15f6-659a-b6acee5b3157'::uuid, 'Increase their base salaries by 20% immediately without any long-term retention clauses.', 3),
  ('c085b46f-c892-893c-6de7-78d2a6690d1d'::uuid, 'f80cdfce-3aaf-15f6-659a-b6acee5b3157'::uuid, 'Provide complimentary luxury personal travel benefits and executive health programs.', 4),
  ('a86ca1a5-d9c3-cca8-7004-e621754c4769'::uuid, 'b1ec0631-4fe9-daea-64ce-53163e482fdd'::uuid, 'Hire a legal team to identify loopholes and exemptions in the legislation to delay public reporting.', 1),
  ('38d65782-a6ae-f509-d500-b26793da611a'::uuid, 'b1ec0631-4fe9-daea-64ce-53163e482fdd'::uuid, 'Conduct a thorough internal Pay Gap and Regression Audit, identify systemic causes of gaps (e.g., underrepresentation in leadership, historical salary compression), design a multi-year remediation plan, and draft a transparent communication strategy for employees and stakeholders.', 2),
  ('d8612d7c-efe7-5234-05a3-808a5b9f732a'::uuid, 'b1ec0631-4fe9-daea-64ce-53163e482fdd'::uuid, 'Re-classify female employees under different job titles to artificially equalize the average salary figures across departments.', 3),
  ('91655a13-06eb-57d3-cab4-8d9c1b66a4c3'::uuid, 'b1ec0631-4fe9-daea-64ce-53163e482fdd'::uuid, 'Issue a company-wide statement declaring that pay gap calculations are structurally flawed and do not reflect internal equity.', 4),
  ('ed1f7aac-9a8e-66a7-42b1-cb3956ffb93e'::uuid, '0aeb97af-6177-d340-ed32-6d0ebd80f010'::uuid, 'Advise the employee to resolve the conflict directly with the director or seek mediation through an external counselor.', 1),
  ('4fef1798-c004-75d1-6a60-48caef53b98c'::uuid, '0aeb97af-6177-d340-ed32-6d0ebd80f010'::uuid, 'Initiate an immediate, impartial, and thoroughly documented formal investigation, separate the reporting employee from the director during the investigation to prevent retaliation, and compile facts for executive review.', 2),
  ('93359f20-9570-9750-cb2f-0edf0a5a0c88'::uuid, '0aeb97af-6177-d340-ed32-6d0ebd80f010'::uuid, 'Discipline the director immediately based on the employee''s report to demonstrate HR’s zero-tolerance policy.', 3),
  ('3993ab1f-dc0c-877a-660a-5004e1896c3e'::uuid, '0aeb97af-6177-d340-ed32-6d0ebd80f010'::uuid, 'Advise the director of the complaint and allow them 5 business days to resolve the issue with the employee.', 4),
  ('92e5b60d-39e6-0511-71fd-063fc2b10866'::uuid, '9c8d295d-973e-62f8-3943-9529a8e46cbe'::uuid, 'Implement the changes immediately and notify the union representatives on the day of the layoffs to prevent labor strikes.', 1),
  ('8fb3f804-f769-741d-e142-64938eeee6be'::uuid, '9c8d295d-973e-62f8-3943-9529a8e46cbe'::uuid, 'Review the Collective Bargaining Agreement (CBA) in detail, initiate early collaborative consultations with union leadership, propose joint retraining initiatives, and execute the workforce reduction strictly in accordance with agreed seniority and severance guidelines.', 2),
  ('25b56206-10a4-eb11-95b9-b920bd8440d7'::uuid, '9c8d295d-973e-62f8-3943-9529a8e46cbe'::uuid, 'Hire temporary non-union workers to replace the current workforce prior to announcing the restructuring.', 3),
  ('0eed8407-ac0d-67d6-b72d-552ba6c359a8'::uuid, '9c8d295d-973e-62f8-3943-9529a8e46cbe'::uuid, 'Petition the labor department to override the collective bargaining agreement based on economic emergency grounds.', 4),
  ('9fbfc953-e231-a5fd-f95b-a459ab259692'::uuid, '2c0a142c-e5ba-4682-44c2-c5519999fa1d'::uuid, 'Establish a strict surveillance policy, install CCTV monitoring, and immediately terminate any employee observed violating PPE rules.', 1),
  ('8bae324b-2e86-39e9-6a71-df52ad2c9702'::uuid, '2c0a142c-e5ba-4682-44c2-c5519999fa1d'::uuid, 'Partner with safety operations to select more ergonomic, comfortable PPE, run interactive safety-awareness workshops, engage workers in peer-led safety committees, and tie manager evaluations directly to department safety compliance metrics.', 2),
  ('cee827e7-b017-ed04-103f-c87a3029730e'::uuid, '2c0a142c-e5ba-4682-44c2-c5519999fa1d'::uuid, 'Increase the financial fines for safety violations and mandate that employees sign a liability waiver.', 3),
  ('becf3742-8196-a3bf-d7da-9516437e711d'::uuid, '2c0a142c-e5ba-4682-44c2-c5519999fa1d'::uuid, 'Lower the daily production targets to allow employees to work slowly while wearing uncomfortable gear.', 4),
  ('8a48c10e-3886-24bf-e660-47c59a9c8a7e'::uuid, 'c9e9b8a5-9977-bfd2-55f9-80609ba865d6'::uuid, 'Advise the employee that the company cannot accommodate their request due to operational hardship and suggest they apply for long-term disability.', 1),
  ('c7f90ad6-7f22-0bf2-4819-96c3d8e15ecf'::uuid, 'c9e9b8a5-9977-bfd2-55f9-80609ba865d6'::uuid, 'Enforce compliance with disability regulations (e.g., ADA), conduct an interactive process to identify and implement reasonable accommodations, educate the manager on accommodation benefits, and monitor the transition.', 2),
  ('4bc18cc4-8c0e-156f-f548-207c70156165'::uuid, 'c9e9b8a5-9977-bfd2-55f9-80609ba865d6'::uuid, 'Instruct the manager to quietly assign the developer’s high-priority tasks to other team members and transition the developer to basic clerical work.', 3),
  ('470a5f8c-0e15-c8f7-ee0d-f746bf565e75'::uuid, 'c9e9b8a5-9977-bfd2-55f9-80609ba865d6'::uuid, 'Authorize the accommodation but reduce the developer''s base salary to offset the cost of the screen-reader technology.', 4),
  ('2fef4208-9047-d659-880c-0de0347dc6ab'::uuid, '11082ac1-ab79-bfad-17ea-6c886ca1bcc9'::uuid, 'Risk: Minor budget variances; corrective action is to transfer contractor expenses to the general HR budget.', 1),
  ('3369835d-10a1-d8e1-f904-37b8f8ccd41b'::uuid, '11082ac1-ab79-bfad-17ea-6c886ca1bcc9'::uuid, 'Risk: Severe legal and financial penalties for worker misclassification (IRS/Department of Labor); corrective action is to conduct an audit of all contractor roles, re-classify misclassified workers as permanent employees, and establish strict hiring criteria.', 2),
  ('cc2db819-f050-f4ab-1b94-c0e9d9902afb'::uuid, '11082ac1-ab79-bfad-17ea-6c886ca1bcc9'::uuid, 'Risk: Internal communication issues; corrective action is to require contractors to sign standard non-disclosure agreements.', 3),
  ('6f3563b2-30a6-7880-d73d-ca4a3072438e'::uuid, '11082ac1-ab79-bfad-17ea-6c886ca1bcc9'::uuid, 'Risk: High operational expenses; corrective action is to renegotiate lower hourly rates with all current independent contractors.', 4),
  ('cfde0a08-385f-781f-275f-3e347a8d24ec'::uuid, '5a2f8c36-415b-350c-b9dc-b276ec9c3f0f'::uuid, 'Launch a series of mandatory unconscious bias workshops and publish a diversity pledge on the corporate website.', 1),
  ('c48ee52b-3f8a-1538-2335-b24d86f922b4'::uuid, '5a2f8c36-415b-350c-b9dc-b276ec9c3f0f'::uuid, 'Design a systemic strategy linking DEI metrics to executive compensation, audit talent pipelines and promotional policies for bias, establish Employee Resource Groups (ERGs) with executive sponsors, and report progress transparently.', 2),
  ('caba35a6-6317-44ea-1cd1-40229429266e'::uuid, '5a2f8c36-415b-350c-b9dc-b276ec9c3f0f'::uuid, 'Establish hiring quotas for underrepresented groups and implement separate, relaxed performance standards for diverse hires.', 3),
  ('626f13c0-9b42-90af-74c2-8da5687a487e'::uuid, '5a2f8c36-415b-350c-b9dc-b276ec9c3f0f'::uuid, 'Offer optional multicultural celebrations and encourage employees to share their personal stories on internal social channels.', 4),
  ('a68f7977-b8c8-4ad8-5f82-08b623c0cf03'::uuid, '5be44a00-b9e2-afee-b501-a758a154f7f1'::uuid, 'Notify the regional VP of Sales to allow them to review the report and prepare a response for the executive committee.', 1),
  ('2910d3cd-8dd7-d9d7-76b6-f1ac0c526923'::uuid, '5be44a00-b9e2-afee-b501-a758a154f7f1'::uuid, 'Acknowledge receipt of the report, protect the whistleblower’s confidentiality, initiate a secure independent investigation in partnership with legal and finance, and take appropriate disciplinary action if the allegations are validated.', 2),
  ('1f6c1caf-8761-befc-e0ab-cfe863cbe008'::uuid, '5be44a00-b9e2-afee-b501-a758a154f7f1'::uuid, 'Disclose the details of the report to the sales team to gather peer feedback and identify the anonymous whistleblower.', 3),
  ('e6e0bbe9-0f45-58f2-3745-7c0338c80059'::uuid, '5be44a00-b9e2-afee-b501-a758a154f7f1'::uuid, 'Dismiss the report as an internal administrative dispute unless the whistleblower provides their legal name.', 4),
  ('5e7444c4-b098-558d-fe79-563567d2ae0d'::uuid, 'a38e050d-07ef-241f-42b4-0cffa8daf388'::uuid, 'Instruct the researchers to backdate their renewal forms to ensure the audit records appear compliant.', 1),
  ('695f049e-36f1-8393-ca86-3dd2cf34f5a6'::uuid, 'a38e050d-07ef-241f-42b4-0cffa8daf388'::uuid, 'Immediately suspend the researchers from active clinical trials, coordinate expedited recertification training, report the non-compliance transparently to the executive leadership, and implement an automated certification tracking system.', 2),
  ('b358f514-d297-49d3-a115-be87026b4bef'::uuid, 'a38e050d-07ef-241f-42b4-0cffa8daf388'::uuid, 'Delay the FDA audit until all researchers have naturally renewed their certifications.', 3),
  ('d5119ddd-8cdc-541f-71e3-677b22ab47f0'::uuid, 'a38e050d-07ef-241f-42b4-0cffa8daf388'::uuid, 'Replace the researchers with certified administrative staff to manage the laboratory during the audit.', 4),
  ('20f6ec88-9f18-bc4b-7ed6-d49b0b1bf443'::uuid, 'bffdc00e-68a0-61d5-9685-428a83d4e721'::uuid, 'Enforce the non-compete agreement immediately by filing a lawsuit against the engineer and the competitor.', 1),
  ('f16af2c3-52f3-7f39-f6c2-22d4bb7ac9a2'::uuid, 'bffdc00e-68a0-61d5-9685-428a83d4e721'::uuid, 'Conduct a thorough Exit Interview, review the signed agreement in coordination with legal to assess local legal enforceability, verify that the engineer does not possess proprietary physical/digital files, and remind them of ongoing confidentiality obligations.', 2),
  ('685c72d1-7502-eb5c-dcc0-cf57438d0164'::uuid, 'bffdc00e-68a0-61d5-9685-428a83d4e721'::uuid, 'Contact the competitor directly to demand they withdraw their employment offer to the engineer.', 3),
  ('eda763e0-7279-4a97-99ac-9584fd730a84'::uuid, 'bffdc00e-68a0-61d5-9685-428a83d4e721'::uuid, 'Abolish all non-compete agreements and allow the engineer to transfer all files freely to preserve positive relations.', 4),
  ('95d08e1b-1ba2-f8ac-abd1-61a2df021b93'::uuid, '61cc023f-e9f4-6daa-66aa-9b1a2038aa89'::uuid, 'Approve the termination immediately to support the plant manager’s authority on the floor.', 1),
  ('f48d1858-76bc-2433-be67-01487f39849e'::uuid, '61cc023f-e9f4-6daa-66aa-9b1a2038aa89'::uuid, 'Advise the plant manager to place the employee on immediate paid administrative suspension, conduct a neutral fact-finding investigation, review the employee''s full historical file, and apply progressive discipline (e.g., written warning and mediation) instead of immediate termination.', 2),
  ('db209394-16fd-8806-a3bb-bae5b3904173'::uuid, '61cc023f-e9f4-6daa-66aa-9b1a2038aa89'::uuid, 'Instruct the plant manager to issue a formal apology to the employee to prevent any potential labor disputes.', 3),
  ('19ffd34e-aee1-6880-1e28-cee503779092'::uuid, '61cc023f-e9f4-6daa-66aa-9b1a2038aa89'::uuid, 'Advise the manager to assign the employee to more difficult, isolated tasks until they resign voluntarily.', 4),
  ('e6d28a5b-6a0d-b109-82de-79b6b37ea972'::uuid, 'ac69a64c-af58-20dd-8e60-a41d68433c27'::uuid, 'Suggest the company lock out the union workers to force compliance with the proposed salary terms.', 1),
  ('dc9432a6-85c8-cd56-6694-0b2e9a493166'::uuid, 'ac69a64c-af58-20dd-8e60-a41d68433c27'::uuid, 'Propose entering into formal, voluntary Mediation or Non-Binding Arbitration facilitated by a neutral, certified third-party labor relations professional.', 2),
  ('08df5dc8-ab1d-6bed-75b5-36b7d832fdc0'::uuid, 'ac69a64c-af58-20dd-8e60-a41d68433c27'::uuid, 'Advise the CEO to negotiate directly with individual employees, bypassing the union representatives.', 3),
  ('a808c7d3-c1a7-9e79-c686-162f9663be93'::uuid, 'ac69a64c-af58-20dd-8e60-a41d68433c27'::uuid, 'Delay negotiations indefinitely to allow the union''s strike fund to deplete naturally.', 4),
  ('672d02a0-2bca-ef1d-2e7f-208015e8d595'::uuid, '0743d6f3-91a6-e423-2945-8bfb29280da5'::uuid, 'Distribute copies of the US Foreign Corrupt Practices Act (FCPA) and require employees to sign a standard receipt form.', 1),
  ('1528b9d4-bddf-389a-0c0d-32b466e11a6b'::uuid, '0743d6f3-91a6-e423-2945-8bfb29280da5'::uuid, 'Design a comprehensive Anti-Bribery Compliance Framework featuring mandatory interactive training with localized scenario simulations, a transparent compliance reporting hotline, clear gift-and-hospitality guidelines, and regular independent audits.', 2),
  ('db1b6ac3-aaec-4ef1-2d34-d2bb5dcac677'::uuid, '0743d6f3-91a6-e423-2945-8bfb29280da5'::uuid, 'Instruct the regional finance team to manage all local facilitation payments through secure, third-party intermediary accounts.', 3),
  ('722d759a-445e-b98a-4b35-c177009149ff'::uuid, '0743d6f3-91a6-e423-2945-8bfb29280da5'::uuid, 'Rely on local legal counsel to handle all public official interactions without internal monitoring.', 4),
  ('392ca6cd-1d24-fbc4-573e-644669263d1c'::uuid, '27048a67-8ae4-76f8-b267-a3d58c897f19'::uuid, 'Instruct the regional office to backdate accommodation records for the past three years to ensure compliance in the current audit.', 1),
  ('63221ec8-f7fb-4d34-ad94-ac0b7c024a08'::uuid, '27048a67-8ae4-76f8-b267-a3d58c897f19'::uuid, 'Design and deploy a standardized Pregnant Workers Accommodation policy, conduct immediate training for all managers and HR staff in that region, establish a centralized document-retention system for all accommodation requests, and perform a follow-up compliance audit in 90 days.', 2),
  ('f48c3814-cd72-568f-dc07-95d0ff2330ef'::uuid, '27048a67-8ae4-76f8-b267-a3d58c897f19'::uuid, 'Advise the regional office to stop approving accommodation requests to avoid documentation challenges.', 3),
  ('e84649b0-baba-b66b-ad99-711cb6ed9a4e'::uuid, '27048a67-8ae4-76f8-b267-a3d58c897f19'::uuid, 'Ignore the gap unless an active legal claim or regulatory complaint is filed by an employee.', 4)
