  ('9d985347-80ec-bb4c-3986-4b6530b21ad0'::uuid, '841fbf97-5d0d-9234-6b32-2de883f36f72'::uuid, 'Fixed Price with Economic Price Adjustment linked solely to CPI index.', 4),
  ('c02a5212-40a0-bb72-dbcb-3d71af21bdf6'::uuid, 'aa08df18-d7ac-776f-25a7-b1dd9754cf56'::uuid, '1 year.', 1),
  ('51dc028c-82fd-d0f4-9a68-570f8bf8da7c'::uuid, 'aa08df18-d7ac-776f-25a7-b1dd9754cf56'::uuid, '10 years.', 2),
  ('c9972b68-c727-cbd8-db9d-96130513f8c6'::uuid, 'aa08df18-d7ac-776f-25a7-b1dd9754cf56'::uuid, '20 years.', 3),
  ('de8d0a8e-7c87-315f-23b6-67830ddd4ace'::uuid, 'aa08df18-d7ac-776f-25a7-b1dd9754cf56'::uuid, '5 years.', 4),
  ('13971a62-8a1c-82ba-e64b-910519ea8259'::uuid, '54a53bbe-f1c1-4253-3efe-82ed0c8fda1a'::uuid, 'Conduct a formal price-reasonableness audit and request clarification to ensure the bidder understood scope requirements.', 1),
  ('1e052c18-1a3b-8654-0d8d-e139ff7f9ba7'::uuid, '54a53bbe-f1c1-4253-3efe-82ed0c8fda1a'::uuid, 'Award the contract immediately without reviewing technical capabilities.', 2),
  ('1bf105d6-4ed8-c7fd-6a08-0b44c7ca901e'::uuid, '54a53bbe-f1c1-4253-3efe-82ed0c8fda1a'::uuid, 'Disqualify all four vendors and cancel the infrastructure initiative.', 3),
  ('40ebeccd-99f7-8daf-023b-57b97810c16c'::uuid, '54a53bbe-f1c1-4253-3efe-82ed0c8fda1a'::uuid, 'Force the second lowest bidder to match the abnormally low price.', 4),
  ('0c653f35-caec-738a-50f0-4cbcee24e1cd'::uuid, 'c4aeb529-e795-282c-77a3-87fc303f4aa9'::uuid, 'Project engineers are legally forbidden from talking to vendors.', 1),
  ('842865e2-2b43-139d-0081-41103b022934'::uuid, 'c4aeb529-e795-282c-77a3-87fc303f4aa9'::uuid, 'Only authorized procurement personnel/contracting officers hold legal authority to commit contract variations.', 2),
  ('f79d1932-0e8f-e591-5ca8-af60276ad04d'::uuid, 'c4aeb529-e795-282c-77a3-87fc303f4aa9'::uuid, 'Scope changes are illegal under international trade law.', 3),
  ('4d5e6c0a-2c61-f61b-0e05-ce19a116692e'::uuid, 'c4aeb529-e795-282c-77a3-87fc303f4aa9'::uuid, 'The vendor failed to submit a patent registration for the change.', 4),
  ('5341f6df-6784-0ed4-aae6-b974eba7ffc3'::uuid, '2dbb3a9e-6aa1-8e99-2383-e443099733ac'::uuid, 'A copy of the contractor''s corporate annual tax return.', 1),
  ('a931c830-4f74-817d-09ca-f19b2aa16f8e'::uuid, '2dbb3a9e-6aa1-8e99-2383-e443099733ac'::uuid, 'An informal email stating that everyone enjoyed working on the project.', 2),
  ('fde025ed-9249-04ff-8e1d-8782c42c5cce'::uuid, '2dbb3a9e-6aa1-8e99-2383-e443099733ac'::uuid, 'A formal Lien Waiver and Certificate of Final Completion releasing the buyer from future subcontractor claims.', 3),
  ('a6b54a20-e741-3583-aea3-a265edd6fcab'::uuid, '2dbb3a9e-6aa1-8e99-2383-e443099733ac'::uuid, 'A verbal promise from the site foreman.', 4)
